// Solution
function validateDockerConfig(config) {
  for (let service of config) {
    let ports = service.ports;
    let seenPorts = new Set();
    for (let port of ports) {
      if (port < 0 || port > 65535) {
        return 'Invalid Docker configuration';
      }
      if (seenPorts.has(port)) {
        return 'Invalid Docker configuration';
      }
      seenPorts.add(port);
    }
  }
  return 'Valid Docker configuration';
}

