class DockerConfigValidator:
  def validate(self, config) -> str:
    for service in config:
      ports = service.get('ports', [])
      seen_ports = set()
      for port in ports:
        if port < 0 or port > 65535:
          return 'Invalid Docker configuration'
        if port in seen_ports:
          return 'Invalid Docker configuration'
        seen_ports.add(port)
    return 'Valid Docker configuration'
